// Transform engagement data with metrics for digest
const engagements = $input.first().json;
const metrics = $node['Calculate Metrics (RPC)'].json;

// Merge engagement data with calculated metrics
const enriched = engagements.map(engagement => {
  const engMetrics = metrics.find(m => m.engagement_id === engagement.id) || {};

  return {
    ...engagement,
    hours_logged: engMetrics.hours_logged || 0,
    budget_burned: engMetrics.budget_burned || 0,
    budget_remaining: engagement.total_budget - (engMetrics.budget_burned || 0),
    burn_rate: engMetrics.hours_logged > 0 ? (engagement.total_budget / engMetrics.hours_logged).toFixed(2) : 0,
    drift_percentage: engMetrics.drift_percentage || 0,
    unscoped_hours: engMetrics.unscoped_hours || 0,
    unscoped_amount: engMetrics.unscoped_hours * (engagement.total_budget / engagement.estimated_hours),
    completion_percentage: engMetrics.hours_logged > 0 ? ((engMetrics.hours_logged / engagement.estimated_hours) * 100).toFixed(0) : 0,
    days_elapsed: Math.floor((new Date() - new Date(engagement.start_date)) / (1000 * 60 * 60 * 24)),
    days_remaining: Math.floor((new Date(engagement.estimated_completion_date) - new Date()) / (1000 * 60 * 60 * 24))
  };
});

// Sort by risk: critical first, then high drift %, then highest budget exposed
const sorted = enriched.sort((a, b) => {
  const riskA = a.drift_percentage > 25 ? 0 : a.drift_percentage > 10 ? 1 : 2;
  const riskB = b.drift_percentage > 25 ? 0 : b.drift_percentage > 10 ? 1 : 2;

  if (riskA !== riskB) return riskA - riskB;
  return b.unscoped_amount - a.unscoped_amount;
});

return sorted;

// Group engagements by partner (owner) and prepare email payloads
const enriched = $node['Enrich & Rank by Risk'].json;
const partners = $node['Fetch Partners'].json;

const grouped = {};
partners.forEach(partner => {
  grouped[partner.id] = {
    partner_id: partner.id,
    partner_name: partner.full_name,
    partner_email: partner.email,
    firm_id: partner.firm_id,
    engagements: []
  };
});

// Assign engagements to their owners
enriched.forEach(eng => {
  if (grouped[eng.owner_id]) {
    grouped[eng.owner_id].engagements.push(eng);
  }
});

// Convert to array and filter out partners with no engagements
const digests = Object.values(grouped).filter(d => d.engagements.length > 0);

return digests;
